/**
 * MedX hint forms runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Helper text and contextual field hints.
 */
const HINT_TOKENS = Object.freeze({
  primary: { value: "forms-hint-primary", scope: "forms" },
  secondary: { value: "forms-hint-secondary", scope: "forms" },
  muted: { value: "forms-hint-muted", scope: "forms" },
  accent: { value: "forms-hint-accent", scope: "forms" },
  surface: { value: "forms-hint-surface", scope: "forms" },
});

const HINT_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const HINT_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const hintRegistry = new Map();
const HINT_listeners = new Set();
let HINT_seq = 0;

function createHintId(prefix = "medx-forms-hint") {
  HINT_seq += 1;
  return `${prefix}-${HINT_seq}`;
}

function registerHint(config = {}) {
  const entryId = config.id ?? createHintId();
  const preset = HINT_PRESETS[config.preset ?? "default"] ?? HINT_PRESETS.default;
  const token = HINT_TOKENS[config.token ?? preset.token] ?? HINT_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: HINT_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  hintRegistry.set(entryId, entry);
  notifyHintListeners("register", entry);
  return entry;
}

function updateHint(id, patch = {}) {
  const entry = hintRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyHintListeners("update", entry);
  return entry;
}

function resolveHint(id) {
  const entry = hintRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listHintEntries(filter = {}) {
  let items = Array.from(hintRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onHintEvent(listener) {
  HINT_listeners.add(listener);
  return () => HINT_listeners.delete(listener);
}

function notifyHintListeners(type, entry) {
  for (const listener of HINT_listeners) {
    try {
      listener({ type, entry, registrySize: hintRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:forms:hint] listener error", err.message);
    }
  }
}

function getHintMetrics() {
  const items = listHintEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(HINT_TOKENS).length,
    presets: Object.keys(HINT_PRESETS).length,
  };
}

async function runMedxHint() {
  console.log("[medx:ui:forms:hint] runtime initialized");
  console.log(`[medx:ui:forms:hint] tokens=${Object.keys(HINT_TOKENS).length} presets=${Object.keys(HINT_PRESETS).length}`);

  const events = [];
  onHintEvent((e) => events.push(e.type));

  const domains = Object.keys(HINT_SUPPLY_CHAIN);
  const presets = Object.keys(HINT_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerHint({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "forms/hint" },
    });
  }

  const first = listHintEntries()[0];
  if (first) updateHint(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getHintMetrics();
  const resolved = first ? resolveHint(first.id) : null;

  console.log(`[medx:ui:forms:hint] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:forms:hint] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:forms:hint] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:forms:hint] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:forms:hint] bootstrap complete");
}

module.exports = runMedxHint;
